import { createContext, useContext, useState, useEffect } from 'react';
import * as api from '../services/api';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const stored = localStorage.getItem('user');
    if (stored) {
      try {
        setUser(JSON.parse(stored));
      } catch {
        localStorage.removeItem('user');
      }
    }
  }, []);

  // 🔹 LOGIN
  const login = async (correo, contraseña) => {
    setLoading(true);

    try {
      const data = await api.login(correo, contraseña);

      if (data?.user) {
        setUser(data.user);
        localStorage.setItem('user', JSON.stringify(data.user));
        return { success: true, user: data.user };
      }

      return { success: false, error: 'Respuesta inválida del servidor' };

    } catch (error) {

      // 🔥 intenta leer el mensaje del backend en todas las formas posibles
      const backendMessage =
        error.response?.data?.message ||
        error.message;

      return {
        success: false,
        error: Array.isArray(backendMessage)
          ? backendMessage.join(", ")
          : backendMessage || 'Error al iniciar sesión'
      };
    }
  };

  // 🔹 REGISTER
  const register = async (correo, contraseña, idFacultad) => {
    try {
      return await api.register(correo, contraseña, idFacultad);
    } catch (error) {
      throw error;
    }
  };

  const logout = async () => {
    setUser(null);
    localStorage.removeItem('user');
    try {
      await api.logout();
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
